    public string Detalle { get; set; }
    public string Consumidor { get; set; }

    public ConsumoPersonal(string codigo, double importe, int cantidad, string fecha, string op, string detalle, string consumidor)
    {
        this.Codigo = codigo;
        this.Importe = importe;
        this.Cantidad = cantidad;
        this.Fecha = fecha;
        this.Op = op;
        this.Detalle = detalle;
        this.Consumidor = consumidor;
    }
}
```
I've converted the struct fields into properties with public getters and setters. In addition, I've added a constructor with parameters that sets the property values to the given values. 

Note that I've also changed the access modifier of the class to `internal` to match the access modifier of the original struct.

